// Example: constraint requires specific shape
interface HasId {
  id: string;
}

function getById<T extends HasId>(items: T[], id: string): T | undefined {
  return items.find(item => item.id === id);
}

// Type passed must have 'id: string'
getById([{ id: '1', name: 'test' }], '1'); // OK

// Add depth limiter to recursive types
type DeepPartial<T, Depth extends number[] = []> =
  Depth['length'] extends 10 ? T : // Stop at depth 10
  T extends object ? {
    [K in keyof T]?: DeepPartial<T[K], [...Depth, 1]>;
  } : T;

// Add explicit type annotation to break complexity
