patterns.codeBlock:
// Wrong
function getStatus(code: number): string {
  if (code === 200) return 'OK';
  if (code === 404) return 'Not Found';
  // Missing return for other codes!
}

// Correct
function getStatus(code: number): string {
  if (code === 200) return 'OK';
  if (code === 404) return 'Not Found';
  return 'Unknown';
}

// Exhaustiveness check pattern
function assertNever(x: never): never {
  throw new Error(`Unexpected value: ${x}`);
}

function handleStatus(status: 'active' | 'inactive'): string {
  switch (status) {
    case 'active': return 'Active';
    case 'inactive': return 'Inactive';
    default: return assertNever(status); // compile error if not exhaustive
  }
}

// Option 1: Initialize at declaration
